exercises.solution_code:
#include <cstddef>
#include <iostream>

int main()
{
    std::size_t s_bool   = sizeof(bool);
    std::size_t s_char   = sizeof(char);
    std::size_t s_short  = sizeof(short);
    std::size_t s_int    = sizeof(int);
    std::size_t s_long   = sizeof(long);
    std::size_t s_float  = sizeof(float);
    std::size_t s_double = sizeof(double);

    std::cout << "bool:   " << s_bool   << " byte(s)\n";
    std::cout << "char:   " << s_char   << " byte(s)\n";
    std::cout << "short:  " << s_short  << " byte(s)\n";
    std::cout << "int:    " << s_int    << " byte(s)\n";
    std::cout << "long:   " << s_long   << " byte(s)\n";
    std::cout << "float:  " << s_float  << " byte(s)\n";
    std::cout << "double: " << s_double << " byte(s)\n";

    std::size_t total = s_bool + s_char + s_short + s_int + s_long + s_float + s_double;
    std::cout << "Total:  " << total << " byte(s)\n";

    return 0;
}

