exercises.solution_code:
#include <cstddef>
#include <iostream>
#include <iomanip>

int main()
{
    int i{};
    double d{};
    std::cin >> i >> d;

    std::cout << "int value: " << i << ", sizeof=" << sizeof(i) << '\n';
    std::cout << std::fixed << std::setprecision(2);
    std::cout << "double value: " << d << ", sizeof=" << sizeof(d) << '\n';
    std::cout << "10 ints: " << sizeof(i) * 10 << " bytes\n";
    std::cout << "10 doubles: " << sizeof(d) * 10 << " bytes\n";

    return 0;
}
